function platformSvg($key, $size = 24) {
    global $platformSvgs;
    if (isset($platformSvgs[$key])) {
        return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="' . (int)$size . '" height="' . (int)$size . '" fill="none" stroke="none" aria-hidden="true">' . $platformSvgs[$key] . '</svg>';
    }
    return '';
}

function platformKeyFromCategory($category) {
    global $platformSvgs;
    $categoryLower = mb_strtolower($category);
    // Match specific platforms first (longer keys first to avoid "Twitter" matching before "Twitter (X.com)")
    $keys = array_keys($platformSvgs);
    usort($keys, function ($a, $b) {
        return strlen($b) - strlen($a);
    });
    foreach ($keys as $key) {
        if ($key === 'Category') continue;
        if (stripos($category, $key) !== false) {
            return $key;
        }
    }
    return 'Category';
}
